{% extends "admin/base_site.html" %}
{% load static %}

{% block title %}Create Clips - {{ video.title }}{% endblock %}

{% block extrahead %}
<style>
.clip-creator {
    max-width: 1200px;
    margin: 20px auto;
}

.video-section {
    background: #f8f9fa;
    padding: 20px;
    border-radius: 8px;
    margin-bottom: 20px;
}

.video-player {
    position: relative;
    width: 100%;
    max-width: 800px;
    margin: 0 auto;
}

.video-player iframe {
    width: 100%;
    height: 450px;
    border: none;
    border-radius: 8px;
}

.timeline-controls {
    margin-top: 15px;
    background: white;
    padding: 15px;
    border-radius: 8px;
    border: 1px solid #ddd;
}

.timeline-bar {
    position: relative;
    height: 40px;
    background: #e9ecef;
    border-radius: 20px;
    margin: 10px 0;
    cursor: pointer;
}

.timeline-progress {
    height: 100%;
    background: #007bff;
    border-radius: 20px;
    width: 0%;
    transition: width 0.1s;
}

.timeline-markers {
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
}

.marker {
    position: absolute;
    top: -5px;
    width: 4px;
    height: 50px;
    cursor: grab;
}

.marker.start {
    background: #28a745;
}

.marker.end {
    background: #dc3545;
}

.marker:active {
    cursor: grabbing;
}

.time-inputs {
    display: grid;
    grid-template-columns: 1fr 1fr 1fr;
    gap: 15px;
    margin-top: 15px;
}

.time-display {
    font-family: monospace;
    font-size: 14px;
    text-align: center;
    padding: 8px;
    background: #f8f9fa;
    border-radius: 4px;
}

.form-section {
    background: white;
    padding: 20px;
    border-radius: 8px;
    border: 1px solid #ddd;
}

.form-grid {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 20px;
}

.form-group {
    margin-bottom: 15px;
}

.form-group label {
    display: block;
    margin-bottom: 5px;
    font-weight: bold;
}

.form-group input,
.form-group textarea,
.form-group select {
    width: 100%;
