}

.btn-success {
    background: #28a745;
    color: white;
}

.btn:hover {
    opacity: 0.9;
}
</style>
{% endblock %}

{% block content %}
<div class="clip-creator">
    <h1>Create Clips: {{ video.title }}</h1>

    <div class="video-section">
        <div class="video-player">
            <iframe 
                id="video-player"
                src="https://iframe.videodelivery.net/{{ video.cloudflare_stream_id }}"
                allow="accelerometer; gyroscope; autoplay; encrypted-media; picture-in-picture;"
                allowfullscreen>
            </iframe>
        </div>

        <div class="timeline-controls">
            <div class="timeline-bar" id="timeline-bar">
                <div class="timeline-progress" id="timeline-progress"></div>
                <div class="timeline-markers">
                    <div class="marker start" id="start-marker" style="left: 10%;"></div>
                    <div class="marker end" id="end-marker" style="left: 60%;"></div>
                </div>
            </div>

            <div class="time-inputs">
                <div class="time-display">
                    Current: <span id="current-time">00:00</span>
                </div>
                <div class="time-display">
                    Start: <span id="start-time">00:00</span>
                </div>
                <div class="time-display">
                    End: <span id="end-time">00:00</span>
                </div>
            </div>

            <div style="text-align: center; margin-top: 15px;">
                <button class="btn btn-primary" onclick="setCurrentAsStart()">Set Current as Start</button>
                <button class="btn btn-primary" onclick="setCurrentAsEnd()">Set Current as End</button>
                <button class="btn btn-success" onclick="previewClip()">Preview Clip</button>
            </div>
        </div>
    </div>

    <div class="form-section">
        <h3>Clip Details</h3>
        <form id="clip-form">
            {% csrf_token %}
            <div class="form-grid">
                <div>
                    <div class="form-group">
                        <label for="title">Clip Title *</label>
                        <input type="text" id="title" name="title" required>
                    </div>

                    <div class="form-group">
                        <label for="piece">Piece</label>
                        <select id="piece" name="piece">
                            <option value="">Select a piece...</option>
                            {% for piece in pieces %}
                            <option value="{{ piece.id }}">{{ piece.title }}</option>
                            {% endfor %}
                        </select>
                    </div>

                    <div class="form-group">
                        <label for="performers">Performers</label>
                        <select id="performers" name="performers" multiple>
                            {% for person in people %}
                            <option value="{{ person.id }}">{{ person.name }} ({{ person.role }})</option>
                            {% endfor %}
                        </select>
                        <small>Hold Ctrl/Cmd to select multiple</small>
                    </div>
                </div>

                <div>
                    <div class="form-group">
                        <label for="description">Description</label>
                        <textarea id="description" name="description"></textarea>
                    </div>

                    <div class="form-group">
                        <label for="technical_notes">Technical Notes</label>
                        <textarea id="technical_notes" name="technical_notes"></textarea>
                    </div>

                    <div class="form-group">
                        <label for="costume_notes">Costume Notes</label>
                        <textarea id="costume_notes" name="costume_notes"></textarea>
                    </div>

                    <div class="form-group">
                        <label for="music_notes">Music Notes</label>
                        <textarea id="music_notes" name="music_notes"></textarea>
                    </div>
                </div>
            </div>

            <input type="hidden" id="start_time" name="start_time" value="0">
            <input type="hidden" id="end_time" name="end_time" value="10">

            <div style="text-align: center; margin-top: 20px;">
                <button type="submit" class="btn btn-success">Create Clip</button>
                <a href="{% url 'admin:archive_video_change' video.id %}" class="btn">Back to Video</a>
            </div>
        </form>
    </div>

    <div class="clips-list">
        <h3>Existing Clips</h3>
        {% for clip in video.clips.all %}
        <div class="clip-item">
            <strong>{{ clip.title }}</strong>
            <div class="clip-time">{{ clip.start_time_formatted }} - {{ clip.end_time_formatted }}</div>
            <p>{{ clip.description|truncatewords:20 }}</p>
        </div>
        {% empty %}
        <p>No clips created yet.</p>
        {% endfor %}
    </div>
</div>

<script>
// Video timeline and clipping functionality
let videoDuration = {{ video.duration_seconds|default:60 }};
let currentTime = 0;
let startTime = 0;
let endTime = Math.min(10, videoDuration);

// Initialize timeline
document.addEventListener('DOMContentLoaded', function() {
    updateTimelineDisplay();
    setupTimelineInteraction();
    setupFormSubmission();
});

function updateTimelineDisplay() {
    // Update progress bar (this would ideally sync with actual video)
    const progress = (currentTime / videoDuration) * 100;
    document.getElementById('timeline-progress').style.width = progress + '%';

    // Update time displays
    document.getElementById('current-time').textContent = formatTime(currentTime);
    document.getElementById('start-time').textContent = formatTime(startTime);
    document.getElementById('end-time').textContent = formatTime(endTime);

    // Update markers
    const startPercent = (startTime / videoDuration) * 100;
    const endPercent = (endTime / videoDuration) * 100;
    document.getElementById('start-marker').style.left = startPercent + '%';
    document.getElementById('end-marker').style.left = endPercent + '%';

    // Update hidden form fields
    document.getElementById('start_time').value = startTime;
    document.getElementById('end_time').value = endTime;
}

function setupTimelineInteraction() {
    const timelineBar = document.getElementById('timeline-bar');
    const startMarker = document.getElementById('start-marker');
    const endMarker = document.getElementById('end-marker');

    // Click on timeline to set current time
    timelineBar.addEventListener('click', function(e) {
        const rect = timelineBar.getBoundingClientRect();
        const percent = (e.clientX - rect.left) / rect.width;
        currentTime = Math.max(0, Math.min(videoDuration, percent * videoDuration));
        updateTimelineDisplay();
    });

    // Drag markers
    makeMarkerDraggable(startMarker, 'start');
    makeMarkerDraggable(endMarker, 'end');
}

function makeMarkerDraggable(marker, type) {
    let isDragging = false;

    marker.addEventListener('mousedown', function(e) {
        isDragging = true;
        e.preventDefault();
    });

    document.addEventListener('mousemove', function(e) {
        if (!isDragging) return;

        const timelineBar = document.getElementById('timeline-bar');
        const rect = timelineBar.getBoundingClientRect();
        const percent = Math.max(0, Math.min(1, (e.clientX - rect.left) / rect.width));
        const time = percent * videoDuration;

        if (type === 'start') {
            startTime = Math.min(time, endTime - 1);
        } else {
            endTime = Math.max(time, startTime + 1);
        }

        updateTimelineDisplay();
    });

    document.addEventListener('mouseup', function() {
        isDragging = false;
    });
}

function setCurrentAsStart() {
    startTime = Math.min(currentTime, endTime - 1);
    updateTimelineDisplay();
}

function setCurrentAsEnd() {
    endTime = Math.max(currentTime, startTime + 1);
    updateTimelineDisplay();
}

function previewClip() {
    // This would ideally seek the video to start time
    alert(`Preview clip from ${formatTime(startTime)} to ${formatTime(endTime)}`);
}

function formatTime(seconds) {
    const hrs = Math.floor(seconds / 3600);
    const mins = Math.floor((seconds % 3600) / 60);
    const secs = Math.floor(seconds % 60);

    if (hrs > 0) {
        return `${hrs.toString().padStart(2, '0')}:${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
    } else {
        return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
    }
}

function setupFormSubmission() {
    document.getElementById('clip-form').addEventListener('submit', function(e) {
        e.preventDefault();

        const formData = new FormData(this);

        fetch(window.location.href, {
            method: 'POST',
            body: formData,
            headers: {
                'X-CSRFToken': document.querySelector('[name=csrfmiddlewaretoken]').value
            }
        })
        .then(response => response.json())
        .then(data => {
            if (data.success) {
                alert('Clip created successfully!');
                location.reload();
            } else {
                alert('Error creating clip: ' + data.error);
            }
        })
        .catch(error => {
            alert('Error: ' + error);
        });
    });
}
</script>
{% endblock %}


