from django import forms
from .models import Clip, Person, Piece

class ClipForm(forms.ModelForm):
    class Meta:
        model = Clip
        fields = [
            'title', 'description', 'start_time_seconds', 'end_time_seconds',
            'piece', 'performers', 'movement_tags', 'technical_notes',
            'costume_notes', 'music_notes'
        ]
        widgets = {
            'description': forms.Textarea(attrs={'rows': 3}),
            'technical_notes': forms.Textarea(attrs={'rows': 3}),
            'costume_notes': forms.Textarea(attrs={'rows': 2}),
            'music_notes': forms.Textarea(attrs={'rows': 2}),
            'movement_tags': forms.TextInput(attrs={
                'placeholder': 'Enter tags separated by commas'
            }),
            'performers': forms.CheckboxSelectMultiple(),
        }

    def __init__(self, *args, **kwargs):
        super().__init__(*args, **kwargs)
        self.fields['performers'].queryset = Person.objects.all()
        self.fields['piece'].queryset = Piece.objects.all()
        self.fields['piece'].empty_label = "Select a piece..."


