            </div>
            {% if clip.description %}
            <p>{{ clip.description }}</p>
            {% endif %}
        </div>
        {% endfor %}
    </div>
    {% endif %}
</div>

<script>
document.addEventListener('DOMContentLoaded', function() {
    let currentTime = 0;
    let startTime = null;
    let endTime = null;
    const videoDuration = {{ video.duration_seconds|default:0 }};

    // Video player communication (simplified - would need proper iframe communication)
    const player = document.getElementById('video-player');
    const timeline = document.getElementById('timeline');
    const clipMarker = document.getElementById('clip-marker');

    // Mark start time
    document.getElementById('mark-start-btn').addEventListener('click', function() {
        startTime = Math.floor(currentTime);
        document.getElementById('start-time-input').value = startTime;
        updateClipMarker();
        alert(`Start time marked at ${formatTime(startTime)}`);
    });

    // Mark end time
    document.getElementById('mark-end-btn').addEventListener('click', function() {
        endTime = Math.floor(currentTime);
        document.getElementById('end-time-input').value = endTime;
        updateClipMarker();
        alert(`End time marked at ${formatTime(endTime)}`);
    });

    // Preview clip
    document.getElementById('preview-clip-btn').addEventListener('click', function() {
        if (startTime !== null && endTime !== null) {
            const previewUrl = `https://iframe.videodelivery.net/{{ video.cloudflare_stream_id }}?startTime=${startTime}s`;
            window.open(previewUrl, '_blank');
        } else {
            alert('Please mark both start and end times first.');
        }
    });

    // Update clip marker on timeline
    function updateClipMarker() {
        if (startTime !== null && endTime !== null && videoDuration > 0) {
            const startPercent = (startTime / videoDuration) * 100;
            const endPercent = (endTime / videoDuration) * 100;
            const width = endPercent - startPercent;

            clipMarker.style.left = startPercent + '%';
            clipMarker.style.width = width + '%';
            clipMarker.style.display = 'block';
        }
    }

    // Timeline click to seek
    timeline.addEventListener('click', function(e) {
        const rect = timeline.getBoundingClientRect();
        const clickPercent = (e.clientX - rect.left) / rect.width;
        currentTime = clickPercent * videoDuration;

        // Update current time display
        document.getElementById('current-time').textContent = formatTime(currentTime);

        // Here you would seek the video player to this time
        // This requires proper iframe communication with Cloudflare Stream player
    });

    // Form submission
    document.getElementById('clip-form').addEventListener('submit', function(e) {
        e.preventDefault();

        const formData = new FormData(this);

        fetch('{% url "admin:archive_video_create_clip_api" %}', {
            method: 'POST',
            body: formData,
            headers: {
                'X-CSRFToken': document.querySelector('[name=csrfmiddlewaretoken]').value
            }
        })
        .then(response => response.json())
        .then(data => {
            if (data.success) {
                alert(data.message);
                location.reload(); // Refresh to show new clip
            } else {
                alert('Error: ' + data.error);
            }
        })
        .catch(error => {
            alert('Error creating clip: ' + error);
        });
    });

    // Clear form
    document.getElementById('clear-form-btn').addEventListener('click', function() {
        document.getElementById('clip-form').reset();
        startTime = null;
        endTime = null;
        clipMarker.style.display = 'none';
    });

    // Format time helper
    function formatTime(seconds) {
        const mins = Math.floor(seconds / 60);
        const secs = Math.floor(seconds % 60);
        return `${mins.toString().padStart(2, '0')}:${secs.toString().padStart(2, '0')}`;
    }

    // Simulate current time updates (in real implementation, this would come from player)
    setInterval(function() {
        currentTime += 1;
        if (currentTime > videoDuration) currentTime = 0;
        document.getElementById('current-time').textContent = formatTime(currentTime);
    }, 1000);
});
</script>

